      "idt": "\n  \n  vec3 InvODT(vec3 linearCV, Chromaticities primaries) {\n    vec3 XYZ = RGBtoXYZ(primaries) * linearCV;\n    if ((primaries.white.x != AP0.white.x) && (primaries.white.y != AP0.white.y)) {\n      XYZ = invert_f33(D60_2_D65_CAT) * XYZ;\n    }\n    linearCV = XYZ_2_AP1_MAT * XYZ;\n    linearCV = invert_f33(ODT_SAT_MAT) * linearCV;\n    vec3 rgbPre = linCV_2_Y_f3(linearCV, CINEMA_WHITE, CINEMA_BLACK);\n    vec3 rgbPost = segmented_spline_c9_rev_f3(rgbPre);\n    vec3 oces = AP1_2_AP0_MAT * rgbPost;\n    return max(oces, 0.0);\n  }\n\n  vec3 InvRRT(vec3 oces) {\n  vec3 rgbPre = AP0_2_AP1_MAT * oces;\n  vec3 rgbPost = vec3(segmented_spline_c5_rev(rgbPre.x),segmented_spline_c5_rev(rgbPre.y),segmented_spline_c5_rev(rgbPre.z));\n  rgbPost = invert_f33(RRT_SAT_MAT) * rgbPost;\n  rgbPost = max(rgbPost, 0.0);\n  vec3 aces = AP1_2_AP0_MAT * rgbPost;\n  aces = max(aces, 0.0);\n  float hue = rgb_2_hue(aces);\n  float centeredHue = center_hue(hue, RRT_RED_HUE);\n  float hueWeight = cubic_basis_shaper(centeredHue, RRT_RED_WIDTH);\n  float minChan = centeredHue < 0.0 ? aces.y : aces.z;\n  float a = hueWeight * (1.0 - RRT_RED_SCALE) - 1.0;\n  float b = aces.x - hueWeight * (RRT_RED_PIVOT + minChan) * (1.0 - RRT_RED_SCALE);\n  float c = hueWeight * RRT_RED_PIVOT * minChan * (1.0 - RRT_RED_SCALE);\n  aces.x = (-b - sqrt(b * b - 4.0 * a * c)) / (2.0 * a);\n  float saturation = rgb_2_saturation(aces);\n  float ycOut = rgb_2_yc(aces);\n  float s = sigmoid_shaper((saturation - 0.4) / 0.2);\n  float reducedGlow = 1.0 + glow_inv(ycOut, RRT_GLOW_GAIN * s, RRT_GLOW_MID);\n  aces = aces * reducedGlow;\n  return aces;\n}\n  vec3 CIO_IDT(vec3 rgb) {\n    vec3 linearCV = moncurve_f_f3(rgb, 2.4, 0.055);\n    vec3 aces = InvODT(linearCV, P3D65_PRI);\n    aces = InvRRT(aces);\n    return min(ACES_to_ACEScct(aces), 1.0);\n  }\n"
