    "ZCam_ZLog2": {
      "id": "ZCam_ZLog2",
      "idt": "\n  \n  float aces_rgc13(float dist, float lim, float thr) {\n    if (dist < thr) return dist;\n    float scl = (lim - thr) / pow(pow((1.0 - thr) / (lim - thr), -1.2) - 1.0, 1.0 / 1.2);\n    float nds = (dist - thr) / scl;\n    float p = pow(nds, 1.2);\n    return thr + scl * nds / (pow(1.0 + p, 1.0 / 1.2));\n  }\n  vec3 CIO_GAMUT_COMPRESS(vec3 aces) {\n    aces = ACES_to_ACEScg(aces);\n    float ach = max(aces.x, max(aces.y, aces.z));\n    float absAch = abs(ach);\n    return ACEScg_to_ACES(vec3(\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.x) / absAch, 1.147, 0.815) * absAch,\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.y) / absAch, 1.264, 0.803) * absAch,\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.z) / absAch, 1.312, 0.880) * absAch\n    ));\n  }\n\n  \n  float vGamma(float x) {\n    float nx = 1.0 - x;\n    return nx * pow(x, 0.7654321) + x * (1.0 - pow(nx, 0.7654321));\n  }\n  vec3 vGamma(vec3 rgb) {\n    return vec3(vGamma(rgb.x), vGamma(rgb.y), vGamma(rgb.z));\n  }\n\n  float Zlog2ToLinear(float x) {\n    return ((pow (113.0, x) - 1.0) / 112.0);\n  }\n  vec3 CIO_IDT(vec3 ZCamZlog2) {\n    float r_lin = Zlog2ToLinear(ZCamZlog2.x);\n    float g_lin = Zlog2ToLinear(ZCamZlog2.y);\n    float b_lin = Zlog2ToLinear(ZCamZlog2.z);\n    vec3 aces = max(vec3(\n      r_lin * 0.59268922 + g_lin * 0.23980554 + b_lin * 0.09364286,\n      r_lin * 0.0078253 + g_lin * 0.99994013 + b_lin * -0.07973914,\n      r_lin * 0.06103745 + g_lin * -0.24592234 + b_lin * 1.13939635\n    ), 0.0);\n    aces = CIO_GAMUT_COMPRESS(aces);\n    return min(vGamma(ACES_to_ACEScct(aces)), 1.0);\n  }\n"
    },
    "LeicaLLog": {
      "id": "LeicaLLog",
      "idt": "\n  \n  float aces_rgc13(float dist, float lim, float thr) {\n    if (dist < thr) return dist;\n    float scl = (lim - thr) / pow(pow((1.0 - thr) / (lim - thr), -1.2) - 1.0, 1.0 / 1.2);\n    float nds = (dist - thr) / scl;\n    float p = pow(nds, 1.2);\n    return thr + scl * nds / (pow(1.0 + p, 1.0 / 1.2));\n  }\n  vec3 CIO_GAMUT_COMPRESS(vec3 aces) {\n    aces = ACES_to_ACEScg(aces);\n    float ach = max(aces.x, max(aces.y, aces.z));\n    float absAch = abs(ach);\n    return ACEScg_to_ACES(vec3(\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.x) / absAch, 1.147, 0.815) * absAch,\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.y) / absAch, 1.264, 0.803) * absAch,\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.z) / absAch, 1.312, 0.880) * absAch\n    ));\n  }\n\n  \n  float vGamma(float x) {\n    float nx = 1.0 - x;\n    return nx * pow(x, 0.7654321) + x * (1.0 - pow(nx, 0.7654321));\n  }\n  vec3 vGamma(vec3 rgb) {\n    return vec3(vGamma(rgb.x), vGamma(rgb.y), vGamma(rgb.z));\n  }\n\n  float leicaLogToLinear(float x) {\n    if (x <= 0.1380) {\n      return (x - 0.09) / 8.0;\n    } else {\n      return (pow(10.0, (x - 0.6) / 0.27) - 0.0115) / 1.3;\n    }\n  }\n  vec3 CIO_IDT(vec3 lLog) {\n    float r_lin = leicaLogToLinear(lLog.x);\n    float g_lin = leicaLogToLinear(lLog.y);\n    float b_lin = leicaLogToLinear(lLog.z);\n    vec3 aces = max(vec3(\n      r_lin * 0.6788911506598102 + g_lin * 0.15886842237789234 + b_lin * 0.16224042703562752,\n      r_lin * 0.04557083087232135 + g_lin * 0.8607127720474108 + b_lin * 0.0937163970408747,\n      r_lin * -0.0004857103518124508 + g_lin * 0.025060195735059528 + b_lin * 0.9754255145687619\n    ), 0.0);\n    aces = CIO_GAMUT_COMPRESS(aces);\n    return min(vGamma(ACES_to_ACEScct(aces)), 1.0);\n  }\n"
    },
    "AppleHLG": {
      "id": "AppleHLG",
      "idt": "\n  \n  vec3 invOutputTransform(vec3 In, float Y_MIN, float Y_MID, float Y_MAX, Chromaticities DISPLAY_PRI, Chromaticities LIMITING_PRI, int EOTF, int SURROUND, bool STRETCH_BLACK, bool D60_SIM, bool LEGAL_RANGE) {\n    mat3 DISPLAY_PRI_2_XYZ_MAT = RGBtoXYZ( DISPLAY_PRI);\n    TsParams PARAMS_DEFAULT = init_TsParams( Y_MIN, Y_MAX, 0.0);\n    float expShift = log2(inv_ssts(Y_MID, PARAMS_DEFAULT)) - log2(0.18);\n    TsParams PARAMS = init_TsParams( Y_MIN, Y_MAX, expShift);\n    vec3 outputCV = In;\n    if (LEGAL_RANGE == true) {\n      outputCV = smpteRange_to_fullRange_f3( outputCV);\n    }\n    vec3 linearCV;\n    if (EOTF == 0) {\n      if (STRETCH_BLACK == true) {\n        linearCV = Y_2_linCV_f3( ST2084_2_Y_f3( outputCV), Y_MAX, 0.0);\n      } else {\n        linearCV = Y_2_linCV_f3( ST2084_2_Y_f3( outputCV), Y_MAX, Y_MIN);\n      }\n    } else if (EOTF == 1) {\n      linearCV = bt1886_f_f3( outputCV, 2.4, 1.0, 0.0);\n    } else if (EOTF == 2) {\n      linearCV = moncurve_f_f3( outputCV, 2.4, 0.055);\n    } else if (EOTF == 3) {\n      linearCV = pow_f3( outputCV, 2.6);\n    } else if (EOTF == 4) {\n      linearCV = Y_2_linCV_f3( outputCV, Y_MAX, Y_MIN);\n    } else if (EOTF == 5) {\n      outputCV = HLG_2_ST2084_1000nits_f3( outputCV);\n      if (STRETCH_BLACK == true) {\n        linearCV = Y_2_linCV_f3( ST2084_2_Y_f3( outputCV), Y_MAX, 0.0);\n      } else {\n        linearCV = Y_2_linCV_f3( ST2084_2_Y_f3( outputCV), Y_MAX, Y_MIN);\n      }\n    }\n    if (D60_SIM == true) {\n      float SCALE = 1.0;\n      if ((DISPLAY_PRI.white.x == 0.3127) && (DISPLAY_PRI.white.y == 0.329)) {\n        SCALE = 0.96362;\n        linearCV = linearCV * (1.0 / SCALE);\n      } else if ((DISPLAY_PRI.white.x == 0.314) && (DISPLAY_PRI.white.y == 0.351)) {\n        SCALE = 0.96;\n        linearCV.x = roll_white_rev( linearCV.x / SCALE, 0.918, 0.5);\n        linearCV.y = roll_white_rev( linearCV.y / SCALE, 0.918, 0.5);\n        linearCV.z = roll_white_rev( linearCV.z / SCALE, 0.918, 0.5);\n      }\n    }\n    vec3 XYZ = DISPLAY_PRI_2_XYZ_MAT * linearCV;\n    if (D60_SIM == false) {\n      if ((DISPLAY_PRI.white.x != AP0.white.x) && (DISPLAY_PRI.white.y != AP0.white.y)) {\n        XYZ = invert_f33(D60_2_D65_CAT) * XYZ;\n      }\n    }\n    \n    if (SURROUND == 0) {\n    \n    } else if (SURROUND == 1) {\n      if ((EOTF == 1) || (EOTF == 2) || (EOTF == 3)) {\n        XYZ = dim_to_dark( XYZ);\n      }\n    } else if (SURROUND == 2) {\n    \n    }\n    linearCV = XYZ_2_AP1_MAT * XYZ;\n    vec3 rgbPost = linCV_2_Y_f3( linearCV, Y_MAX, Y_MIN);\n    vec3 rgbPre = inv_ssts_f3( rgbPost, PARAMS);\n    vec3 aces = inv_rrt_sweeteners( rgbPre);\n    return aces;\n  }\n\n  \n  float aces_rgc13(float dist, float lim, float thr) {\n    if (dist < thr) return dist;\n    float scl = (lim - thr) / pow(pow((1.0 - thr) / (lim - thr), -1.2) - 1.0, 1.0 / 1.2);\n    float nds = (dist - thr) / scl;\n    float p = pow(nds, 1.2);\n    return thr + scl * nds / (pow(1.0 + p, 1.0 / 1.2));\n  }\n  vec3 CIO_GAMUT_COMPRESS(vec3 aces) {\n    aces = ACES_to_ACEScg(aces);\n    float ach = max(aces.x, max(aces.y, aces.z));\n    float absAch = abs(ach);\n    return ACEScg_to_ACES(vec3(\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.x) / absAch, 1.147, 0.815) * absAch,\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.y) / absAch, 1.264, 0.803) * absAch,\n      ach - aces_rgc13(ach == 0.0 ? 0.0 : (ach - aces.z) / absAch, 1.312, 0.880) * absAch\n    ));\n  }\n\n  \n  float vGamma(float x) {\n    float nx = 1.0 - x;\n    return nx * pow(x, 0.7654321) + x * (1.0 - pow(nx, 0.7654321));\n  }\n  vec3 vGamma(vec3 rgb) {\n    return vec3(vGamma(rgb.x), vGamma(rgb.y), vGamma(rgb.z));\n  }\n\n  vec3 CIO_IDT(vec3 cv) {\n    const float Y_MIN = 0.0001;\n    const float Y_MID = 15.0;\n    const float Y_MAX = 1000.0;\n    Chromaticities DISPLAY_PRI = REC2020_PRI;\n    Chromaticities LIMITING_PRI = REC2020_PRI;\n    int EOTF = 5;\n    int SURROUND = 0;\n    bool STRETCH_BLACK = true;\n    bool D60_SIM = false;\n    bool LEGAL_RANGE = false;\n    vec3 oces = invOutputTransform(cv, Y_MIN, Y_MID, Y_MAX, DISPLAY_PRI, LIMITING_PRI, EOTF, SURROUND, STRETCH_BLACK, D60_SIM, LEGAL_RANGE);\n    oces = CIO_GAMUT_COMPRESS(oces);\n    return min(vGamma(ACES_to_ACEScct(oces)), 1.0);\n  }\n"
    },
