      "odt": "\n  \n  float inv_normalizedLogC4ToRelativeSceneLinear(float y) {\n    const float a = (pow(2.0, 18.0) - 16.0) / 117.45;\n    const float b = (1023.0 - 95.0) / 1023.0;\n    const float c = 95.0 / 1023.0;\n    const float s = (7.0 * log(2.0) * pow(2.0, 7.0 - 14.0 * c / b)) / (a * b);\n    const float t = (pow(2.0, 14.0 * (-c / b) + 6.0) - 64.0) / a;\n    return y < (0.0 * s + t) ? (y - t) / s : c + b * (log2(y * a + 64.0) - 6.0) / 14.0;\n  }\n\n  vec3 CIO_ODT(vec3 cct) {\n    \n  vec3 oces = ACEScct_to_ACES(cct);\n  vec3 lc4 = vec3(\n    oces.x * 1.3317489221092088383 + oces.y * -0.19104183113940071872 + oces.z * -0.14070709095573741055,\n    oces.x * -0.0010810260909258689149 + oces.y * 0.99281872149022221866 + oces.z * 0.0082623045998774198513,\n    oces.x * 0.00066398815655771477962 + oces.y * 0.00075151370416279931116 + oces.z * 0.99858449803942103618\n  );\n  lc4.x = inv_normalizedLogC4ToRelativeSceneLinear(lc4.x);\n  lc4.y = inv_normalizedLogC4ToRelativeSceneLinear(lc4.y);\n  lc4.z = inv_normalizedLogC4ToRelativeSceneLinear(lc4.z);\n\n    return lc4;\n  }\n"
